def calculate_discount(price, discount_type, user_status):
    if price <= 0:
        return 0

    if discount_type == "percentage":
        if user_status == "premium":
            return price * 0.8
        else:
            return price * 0.9
    elif discount_type == "flat":
        if user_status == "premium":
            return max(0, price - 20)
        else:
            return max(0, price - 10)

    return price
